import { getRetryableResponse } from "../../src/lib/fetch-helpers";

function mockSingleFetch(responseData, responseCode) {
  global.fetch = jest.fn().mockImplementationOnce(() =>
    Promise.resolve({
      json: () => Promise.resolve(responseData),
      status: responseCode
    })
  );
}
function mockMultipleFetch(responseData, responseCode) {
  let rc = 0;
  global.fetch = jest.fn().mockImplementation((url, fetchOptions) => {
    if (url.includes("correlation_id")) {
      rc++;
      return Promise.resolve({
        json: () => Promise.resolve(responseData[1]),
        status: responseCode[rc]
      });
    } else {
      return Promise.resolve({
        json: () => Promise.resolve(responseData[0]),
        status: responseCode[0]
      });
    }
  });
}

function mockBodyToPath(responseData, expectedUrl) {
  global.fetch = jest.fn().mockImplementation((url, fetchOptions) => {
    // If it's matches what we're expecting
    if (url.startsWith(expectedUrl) && fetchOptions.method === "GET") {
      if (fetchOptions.body) throw new Error("Request with GET method cannot have body.");
      return Promise.resolve({
        json: () => Promise.resolve(responseData[1]),
        status: 200
      });
    } else if (url.includes("correlation_id")) {
      throw new Error("Path not transformed. Was " + url + " method was " + fetchOptions.method);
    } else {
      // Resolves a promise that will kick off the next promise
      return Promise.resolve({
        json: () => Promise.resolve(responseData[0]),
        status: 202
      });
    }
  });
}

xit("Rejects immediately if retries are set to 0", async () => {
  expect.assertions(1);
  try {
    const response = await getRetryableResponse({
      url: "#",
      fetchOptions: {},
      retries: 0
    });
    expect(response).toBe(undefined);
  } catch (e) {
    expect(e).toBeTruthy();
  }
});

xit("Returns successfully if there is a good response first time", async () => {
  const data = {
    test: "test"
  };
  mockSingleFetch(data, 200);
  expect.assertions(1);
  try {
    const response = await getRetryableResponse({
      url: "https://example.com",
      fetchOptions: { method: "GET" },
      retries: 1
    });
    expect(response).toBe(data);
  } catch (e) {
    console.error(e);
  }
});

xit("Retries after the timeout period if it gets back a correlationId", async () => {
  global.jsdom.reconfigure({ url: "https://example.com" });
  const data = [{ correlationId: "testId" }, { test: test }];
  mockMultipleFetch(data, [202, 200]);
  expect.assertions(1);
  try {
    const response = await getRetryableResponse({
      url: "https://example.com?bol=12345",
      fetchOptions: {
        method: "POST",
        params: { customerCode: "1234", carrierCode: "MAEU" }
      },
      retries: 1
    });
    expect(response).toBe(data[1]);
  } catch (e) {
    console.error(e);
  }
});

