xit("Errors if it does not get correlationId", async () => {
  global.jsdom.reconfigure({ url: "https://example.com" });
  const data = [{ billOfLading: "12345" }, { test: test }];
  const error = "Response does not contain 'correlationId' which is required for making another request.";
  mockMultipleFetch(data, [202, 204, 204]);
  expect.assertions(1);
  try {
    const response = await getRetryableResponse({
      url: "https://example.com?bol=12345",
      fetchOptions: { method: "POST" },
      retries: 3,
      timeout: 100
    });
    expect(response).toBeFalsy();
  } catch (e) {
    expect(e).toEqual(new Error(error));
  }
});

