xit("Throws error if response is an Array with more then one element", async () => {
  const data = [{ correlationId: "testId" }, { testA: "testA" }, { testB: "testB" }];
  const error =
    "Response is a collection with zero or more then one element. It cannot be handled by multiple retryable requests.";
  mockSingleFetch(data, 202);
  expect.assertions(1);
  try {
    await getRetryableResponse({
      url: "https://example.com",
      fetchOptions: { method: "POST" },
      retries: 1
    });
  } catch (e) {
    expect(e).toEqual(new Error(error));
  }
});

