xtest.each`
  waitTimeUnit      | waitTime    | timeout
  ${"SECONDS"}      | ${1}        | ${1000}
  ${"MILLISECONDS"} | ${100}      | ${100}
  ${"MINUTES"}      | ${2 / 60}   | ${200}
  ${"HOURS"}        | ${3 / 3600} | ${300}
`(
  "Picks up the right timeout from the API response - retryUnit $waitTimeUnit",
  async ({ waitTimeUnit, waitTime, timeout }) => {
    global.jsdom.reconfigure({ url: "https://example.com" });
    const data = [
      {
        correlationId: "testId",
        waitTimeUnit,
        waitTime
      },
      { test: test }
    ];
    mockMultipleFetch(data, [202, 200]);
    expect.assertions(2);
    try {
      const startTime = Date.now();
      const response = await getRetryableResponse({
        url: "https://example.com?bol=12345",
        fetchOptions: { method: "POST" },
        retries: 1
      });
      const endTime = Date.now();
      expect(response).toBe(data[1]);
      expect(endTime - startTime).toBeGreaterThanOrEqual(timeout);
    } catch (e) {
      console.error(e);
    }
  }
);

xtest.each`
  url                                                                         | body                                                   | getUrlPath                                        | expectedGETUrl
  ${"/transport-documents/parties"}                                           | ${{ tpDoc: "123456789" }}                              | ${"/transport-documents/parties/123456789"}       | ${"https://example.com/transport-documents/parties/123456789"}
  ${"/transport-documents/parties"}                                           | ${{ tpDoc: "123456789", shipment: "12345" }}           | ${"/transport-documents/123456789/parties/12345"} | ${"https://example.com/transport-documents/123456789/parties/12345"}
  ${"/transport-documents"}                                                   | ${{ tpDoc: "123456789" }}                              | ${""}                                             | ${"https://example.com/transport-documents"}
  ${"/transport-documents/parties"}                                           | ${{ tpDoc: "123456789" }}                              | ${"/transport-documents/123456789/parties"}       | ${"https://example.com/transport-documents/123456789/parties"}
  ${"/transport-documents/parties?brand_code=MAEU&customer_code=10000007951"} | ${{ tpDoc: "SIPAY0001", shipmentNumber: "SIPAY0001" }} | ${"/transport-documents/SIPAY0001/parties"}       | ${"https://example.com/transport-documents/SIPAY0001/parties?brand_code=MAEU&customer_code=10000007951&correlation_id=testId"}
`(
  "Transforms the GET path from $url to $expectedGETUrl when using getUrlPath of $getUrlPath",
  async ({ url, body, getUrlPath, expectedGETUrl }) => {
    global.jsdom.reconfigure({ url: "https://example.com" });
    const data = [
      {
        correlationId: "testId"
      },
      { test: "testResult" }
    ];
    mockBodyToPath(data, expectedGETUrl);
    expect.assertions(1);
    try {
      const response = await getRetryableResponse({
        url: "https://example.com" + url,
        fetchOptions: { method: "POST", body: JSON.stringify(body) },
        getUrlPath,
        retries: 1
      });
      expect(response).toBe(data[1]);
    } catch (e) {
      console.error(e);
    }
  }
);

xtest("sending the body as a plain JS object throws an error when trying to transform it", async () => {
  global.jsdom.reconfigure({ url: "https://example.com" });
  const data = [
    {
      correlationId: "testId"
    },
    { test: "testResult" }
  ];
  mockBodyToPath(data, "https://example.com/expected/url");
  expect.assertions(1);
  try {
    const response = await getRetryableResponse({
      url: "https://example.com/post/endpoint",
      fetchOptions: { method: "POST", body: { tpDoc: 1234 } },
      getUrlFormat: "/getUrlFormat/{tpDoc}",
      retries: 1
    });
    expect(response).toBe(data[1]);
  } catch (e) {
    expect(e).toBeTruthy();
  }
});
